(window.webpackJsonp=window.webpackJsonp||[]).push([[64],{327:function(v,_,p){"use strict";p.r(_);var t=p(13),a=Object(t.a)({},(function(){var v=this,_=v._self._c;return _("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[_("h1",{attrs:{id:"阳春终至"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#阳春终至"}},[v._v("#")]),v._v(" 阳春终至")]),v._v(" "),_("h2",{attrs:{id:"失败如我"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#失败如我"}},[v._v("#")]),v._v(" 失败如我")]),v._v(" "),_("p",[v._v("只有当潮水退去的时候，我们才会停下来思索，我们究竟需要的是什么。")]),v._v(" "),_("p",[v._v("反思一下四年的生活，或许我从来也不曾知晓过自己想要什么，或是随波逐流，或是随遇而安。偶尔有所行动，也只不过是漫无目的地尝试。我从未找寻过我真正所热爱的，也从未遇见过自己所期待的。过去，未来，现在。")]),v._v(" "),_("p",[v._v("曾经就读的经济学专业里，大家其实待我不薄。那一段日子，尽管有一些为情所困，但总的来说依然是开心的。离开的原因，一方面也不过是因为对计算机的些许倾向，另一方面则是追寻无果的自我逃避。但情绪影响下的心态一旦失陷就无所弥补，于是也就铸就了我大学的第一次大失败。")]),v._v(" "),_("p",[v._v("当我从失败里走出时，我的性情变得更加随心所欲。随心所欲的旅行，随心所欲的竞赛，除了不敢再随心所欲的喜欢一个人，我已经尝试了随心所欲的一切。实验室和竞赛的光环加持，让我一步步从众人眼中的小雷变成了大佬口中的雷佬。可我知道，我其实依然什么都不是，但曾经永远回不来了。")]),v._v(" "),_("p",[v._v("犹豫就会败北，果断一定白给，其实未必，很多时候差的也许就是那么一点果断。不管是果断的断了舍离，还是干净利落的选择表白，后面都未必会有这么多乱七八糟的境遇。所有感情的失望，终究会成为成长的垫脚石。")]),v._v(" "),_("p",[v._v("前途有些茫然。本专业自然不是一个理想的归宿，虽然我熟悉代码，但我并不热爱代码。一年的考研之路蹉跎的不仅是岁月，更是曾有过的一切上进的美好的愿景。我明显感受到了自己的颓废，却又无力去改变现实。曾经的我总是很消极的看待世间的一切，但却也从来未曾想过躺平。而今，我累了。")]),v._v(" "),_("p",[v._v("考研前曾经想过无数种退路，可真到了这个时候，我却犹豫了。骨子里的随波逐流不是一时半会儿所能改变的，我也从来没有过期待的未来。")]),v._v(" "),_("p",[v._v("不过，我会记得你所说的，放下即自由吧，就放心地飞，有意义就足够了。")]),v._v(" "),_("h2",{attrs:{id:"清明落雨"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#清明落雨"}},[v._v("#")]),v._v(" 清明落雨")]),v._v(" "),_("p",[v._v("2021年4月2日，阴有小雨。")]),v._v(" "),_("p",[v._v("下午面试了字节跳动，平心而论，字节的面试官是我面试以来感觉最好的。提的每一个问题都非常有条理，环环相扣。后面的问题与前面的问题紧密相关，而且会很有耐心的给你进行讲解，做一些小小的提醒。要不是我水平不够，我真的挺想去的。")]),v._v(" "),_("p",[v._v("然后就是在期待了半个月以后终于拿到了一个offer，虽然待遇可能真的没法跟其他家相比。但是钱对我而言确实不像对于别人那么重要，当然具体是多少我也不确定，细节我还没拿到。估计一年也就挣个二十来个的样子吧。也无所谓了 就这样吧，混一天算一天，没期待了。")]),v._v(" "),_("p",[v._v("面试前突发奇想，清明了还是要出去一趟，于是乎现在也就在路上了。K101的列车员依然一口熟悉的京片子，车也是一如既往的破烂。但我忽然意识到，这可能是我最后一次坐这车了。在宣城还没有通高铁的日子里，每一次从南京到宣城，几乎都坐的是这趟车。慢悠悠的开过宁芜铁路，走进皖南的春夏秋冬。终于，四年过去了，我也即将告别了。")]),v._v(" "),_("p",[v._v("平心而论，我还是很感激这里的一切的。花草树木，春夏秋冬，爱过的，错过的。以及一种似乎应该被称为青春的东西。这里的平台，是我的水平下所能承受的最好的。无论别人怎么看待合工大，但起码，合工大绝对对得起我。")]),v._v(" "),_("p",[v._v("这一年里需要感谢的人还挺多的。首先感谢春华老师和406电子设计网络会所的everyone，不论是考研还是秋招春招的每一次笔试面试，我花了最多的时间在406度过。406的每一个人、电设的每一个人，都待我相当不错。不论是开心的时候、难过的时候，还是拼搏的时候、泄气的时候，电设始终与我同在。也祝电设的每一个人都有着光明的前途。")]),v._v(" "),_("p",[v._v("其次感谢合肥本部的诸位朋友们。是你们一直以来的不离不弃温暖了我的大三大四生活，让我在内卷失败的谷底里看见更多清新的空气。感谢515和619的室友们，以及17经济、17电信科、17物联网所有一直关心我鼓励我的人们。或得意或失意，或成功或失败。有上岸清北华五的巨佬，也有一时失意的落魄者。但无论如何，一段旅途已经走到了终点，新的旅程即将启航。大家终将拥有光明的未来。")]),v._v(" "),_("p",[v._v("再后面再特别的感谢一些人吧。18的hyz，rxy，dh，hym，19的zc，ll，th，hh，hjf，lsl，fyp，wxp，dxy等。感谢你们日常生活中对我的关心和帮助。尽管可能很多时候我会疏于关心，但起码心意到了，就很好。")]),v._v(" "),_("p",[v._v("感谢18的dcc，感谢在考研最开始的时候的偶然相遇，让我定下了北航的目标。无论结果如何，起码让我有了一个还算靠谱的专业课基础。感谢19的zxy，虽然后来发生了挺多不愉快，但在我最困惑迷茫和无助的时候，你是我撑下来的唯一动力。感谢19的fmy，你就像一轮明月，用柔和的光芒照亮着我，驱除着我内心里最阴暗的角落。感谢19的wzj学姐，你让我看到了一个人优秀的模样，让我知道人应该怎样才能变得更好。")]),v._v(" "),_("p",[v._v("最后的最后，感谢某位跟我首字母完全一致的。。。可能应该也许好像算是朋友吧。。。时光沉淀了太多，让我已经难以分清，孰真孰假，孰对孰错，孰是孰非。在不可预见的未来里，行星的轨道是否会有交集。。。谁也不知道。。。")]),v._v(" "),_("p",[v._v("我也不知道后来的人会怎样评价我，我也不像大家所认为的那么叱咤风云。有的人尊称一声佬，或许是我确然的帮助过谁，亦或者只是人云亦云罢了。但至于我本身，只不过是互联网隐藏下的，一个卑微弱小的灵魂罢了。")]),v._v(" "),_("h2",{attrs:{id:"再见姑苏"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#再见姑苏"}},[v._v("#")]),v._v(" 再见姑苏")]),v._v(" "),_("p",[v._v("当这个名叫大学的堆栈即将填满，回忆的指针在其间凌乱。往日的细节似乎已经无从查找，遍历的顺序也无关紧要。但尽管如此，在这江南的一座座城里，依然可以拾起这许多的记忆，就像在风中寻觅着你，无论归期。")]),v._v(" "),_("p",[v._v("180千米，是苏州与宣城的距离。忽略郎溪广德的崇山峻岭，跨越太湖湖水的波光粼粼。四年大学生涯，四次到访苏州，每一次都是因为不一样的原因，也留下了不一样的记忆。")]),v._v(" "),_("p",[v._v("2018年的清明时节，洗礼着城市的是纷纷的落雨。与刘总一起走过太湖之滨，品尝美味的苏式汤面，看北寺塔前雨水成溪。心心念念的苏州博物馆前，人潮堪比那天的大雨。乘兴而来，却因着大雨终究扫兴而去。就像那是我卑微的喜欢，开始的快，却也终究无所结果。")]),v._v(" "),_("p",[v._v("2018年的冬天，江南大雪纷飞。离开落雪的上海滩，走进清寂的甪直古镇。雪后的古镇，一切都是清亮的颜色。到达苏州城时已经入夜，夜里的一切都是绚丽夺目的光彩。流灯观前，溢彩山塘，似有所动，未有所动。我犹记得那年雪落时节唱过的歌，却可能再也见不到唱歌的人。")]),v._v(" "),_("p",[v._v("再次迈入苏州，是2019年的五一时节。从浙江南浔徒步迈过省界，进入苏州吴江的最南端。震泽，黎里，水乡古镇，风物人情。日暮时分的金鸡湖畔，与网友的初次相遇。至今也不知道，那时到底有没有一点喜欢，但或许是有的吧。苏州博物馆依然预约不上，于是我去了拙政园。苏州园林荟萃，但似乎拙政园为最。")]),v._v(" "),_("p",[v._v("当一切在疫情里经历了一年的停摆，再次来到苏州，一切依然似乎从前。从苏州站旁的旅舍醒来，看过护城河上的平门，坐上公交去往三年前曾去的同德兴面馆。从网师园慢慢逛到苏州博物馆，终于圆满了一直以来的遗憾。金鸡湖的白天虽然不如夜色精彩，但也是同样的绚烂。")]),v._v(" "),_("h2",{attrs:{id:"摸鱼人生"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#摸鱼人生"}},[v._v("#")]),v._v(" 摸鱼人生")]),v._v(" "),_("p",[v._v("偶然翻了翻表白墙，看到一个奇怪的话题。关于转专业会不会孤独这个问题，似乎每个人都有自己的想法，但是绝大多数人给出的答案都是偏向于No的一边的。看了看我的列表里面，转专业大佬大概有个30个左右吧这样子。但是似乎混成我这样子的，倒也少见就是了。我甚至不知道我应该算成功还是失败，也不知道如果不转专业我的日子是好还是坏，不过应该不会现在一样拿一个年薪二三十万的offer就是了。")]),v._v(" "),_("p",[v._v("我转专业的时候发生了一些很不愉快的事情，跟原来专业的一大部分人都闹翻了，转专业以后特别忙而且学不懂，孤独是必然很孤独的。其实我们宿舍关系倒还挺不错的，但是某种程度上也就仅限于此了。大概转专业还没多久的时候，我就感觉到这个班级似乎是个挺难融入的集体，每个圈子都有每个圈子的想法。我很快就放弃了好好融入班级的打算，但很快发现离开班集体架构，专业也就那么回事吧。大二的时候主要交好三班的几个熟悉的同学，然后也去蹭一班的团建聚会。热闹归热闹，但偶尔的热闹完了还是很孤独的。")]),v._v(" "),_("p",[v._v("虽然说我很水而且社交面积挺广的，但真的有深度的交情还是挺少的，我的心理防线相当坚实，以致于很少有人能够去相对深刻的理解我。对于防线以外的人，我已经基本上不会有任何感情触动了，以致于很多时候都特别无聊。但我会特别去相信任何一个能够突破我心理防线的人，会把我脆弱的玻璃心毫无保留的呈现出来，也会因此被伤的特别深。于是我的生活里最多的，大约也就是伤害和孤独了吧。")]),v._v(" "),_("p",[v._v("大二下加入了实验室以后基本上生活主要就是围绕实验室了，跟自己的班级甚至是专业同级的接触平心而论都不多，组队什么基本上就室友，互评什么的常年排名倒数。列表里面大半的人基本上都是学弟学妹什么的了，在牛头冲里多混了几年，虽然不一定比他们长多少岁，但是总归经验什么的多了一些。我一直试图以为自己跟他们是同级，但终究还是不可能的啊。唉，终于还是老了。")]),v._v(" "),_("p",[v._v("如果这段时间不出意外的话，我可能就可以安心开启人生的下一段旅途了。没有研究生读，虽然有点遗憾，但也只是大部分旁观者的遗憾吧。对于我本人而言，其实什么都无所谓，日子能混下去就不错，要是能再混的好一点，那就更完美了。")]),v._v(" "),_("p",[v._v("晚上也谈论到了关于年龄的问题，似乎像我这种相对年轻的大学生，很少会有特别卷的吧。没有经历许多社会的毒打，没有经历过特别重的高压，也不会懂得卷的可贵品质。或许如果我能够去像其他大佬一样，早早卷起来的话或许也是另一种生活了吧。")]),v._v(" "),_("p",[v._v("晚安，摸鱼人生。")]),v._v(" "),_("h2",{attrs:{id:"生之无奈"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#生之无奈"}},[v._v("#")]),v._v(" 生之无奈")]),v._v(" "),_("p",[v._v("一个月来的第四次闪现，地点是小城仪征。或许这一次旅途结束以后，我暂时不会再有出门的念头了。旅行是为了缓解自己的无聊，可旅途本身却让自己变得更加无聊。简单算了下，三月开学到现在花掉了四千多点，去掉两千不到的日常里面杂七杂八的开支，大概有两千多花在了旅途上。值得吗？似乎也不算很值的样子。我确实看到了江南春日里别样的风景，但那终究只是一段段零散的记忆罢了。")]),v._v(" "),_("p",[v._v("列表充斥着悍不畏死的卷王，毅然决然的在保研加分一线冲锋陷阵。也有手握好几篇SCI的大佬，在学术道路上一路凯歌。但更多的人都只是需要考研的普通人，胜者只是被导师push的学术萌新，而败者也不过是考研二百五十余万炮灰中普普通通的一份子罢了。关于考不考研和怎么选专业的事情，每个人都有每个人自己的想法。生化环材们吐槽自己的所学脱离现实，找不到工作。机械土木们吐槽自己的所学层次太低，看不到希望。但其实哪有那么多高大上的工作需要去做呢？当每一个人都在追求更高的目标的时候，卷就无可避免的降临了。")]),v._v(" "),_("p",[v._v("工作永远是有限的，那只能让更高级的人来做更低级的工作。宇宙机和宇宙金的热门不是偶然，他们共同的特点是生产力完全依赖于人而非物。你只需要一台电脑就可以写出给千千万万人服务的代码，就可以参与金融市场的惨烈搏杀。当一个人的工作成本越低的时候，他所能拿到的报酬也就越高，但同时他被压榨的也就越狠。即便如此，宇宙机和宇宙金也走向了两个极端。宇宙机依靠超额的时长来榨取日益微薄的利润，从而维持整个行业的相对高薪。而宇宙金则为了维护行业的绝对高薪，而不断拉升自己的门槛，阻挡外人的进入。但渐渐的，金融的工作强度越来越大，计算机的门槛开始越来越高。两者终将在内卷中走向同一结果，大约类似于如今的医学，门槛与成本均极高，但收益不足。")]),v._v(" "),_("p",[v._v("那么，我们再回到大学本身。研究型大学，培养的是研究型的人才。研究型人才读硕士博士一路深造，天经地义。于是当我们读完本科发现，我们所学的东西全部是为了我们进一步深造而准备的。寄希望于通过我们学到的东西去找工作，难度必然很大。当我们按部就班的读完四年，在内卷中失败丢失了保研名额，其实我们就已经是被学校所放弃的人了。但是惯性总会驱动着我们考研，因为对于绝大多数人来说除了读研别无他法。一个从未学到过本专业赖以谋生的技能，甚至连自己的毕业设计都难以完成的人，怎么去从事本专业相关的工作呢？")]),v._v(" "),_("p",[v._v("当金融绑架了市场，房价便成为了悬在当代人头上的一把利刃。尽管事实而言房价并不是人生唯一的意义，但对于大多数人而言，房依然是使人隐隐作痛的心病。自从城市化快速发展以来，大量的商品房拔地而起，但大家都普遍忽略了一个现实：老旧的无学区的住宅，价值只会越来越低，甚至趋近于0。因此即使是住宅置换，依然需要掏出百万级以上的差价。我亲戚家卖掉了北京三套地段尚可甚至还有学区的老旧住房，才成功换得一套全新的商品楼盘。房地产的泡沫只是表象，即使未曾戳破，他也只是一个洗劫财富的工具。等到中国的城市化基本完成的时候，我们的房子也基本上到了价值基本归零的时候，那时的拆迁，也就意味着你的资产被剥削一空。中国不像西方，你对你的房屋没有完整的所有权，你无法自行赋予其新的价值，只能板等房屋随着自身的老化而凋敝，而失去价值。于是乎新房永远都供不应求，这样的话房价也就永远不可能跌落。")]),v._v(" "),_("p",[v._v("似乎这么说起来的话，人生好像过于悲观了。但是人生本来就是苦的，甜蜜的人生只是少数人的幸运，而大多数人注定劳碌无为。我害怕去幻想所有美好的事物，害怕去寻觅爱情。我期待，却又忐忑。其实所有的无疾而终，都只不过是临阵退缩罢了。当我自己都不敢去相信自己的时候，又有谁敢去相信你呢？终于，我应当是看开了。能力不够的时候就不应该去想乱七八糟的，又不敢冲，又舍不得，那不就是徒增烦恼罢了嘛。")]),v._v(" "),_("h2",{attrs:{id:"彩金·宣州"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#彩金·宣州"}},[v._v("#")]),v._v(" 彩金·宣州")]),v._v(" "),_("p",[v._v("从大二到大四，每当我心情好或是不好的时候，我都会骑上我的老伙计，然后来到这里。就在湖边上，依靠在自行车上，吹一会儿湖风，看一会儿湖水。")]),v._v(" "),_("p",[v._v("这里的湖水相当清澈，忠实的书写着天空的模样。天空湛蓝的时候，湖水也是透亮。天空阴沉的时候，湖水也是深青。阳光洒落的时候，湖面一片的波光粼粼。夕阳西下的时间，又是一片火红的苍凉。待到星光闪烁，夜色下的湖边伸手不见五指，遥看另一侧城市的点点灯火，又仿若是另一个世界。")]),v._v(" "),_("p",[v._v("站在北岸大堤上举目四望，湖畔尽是山野之所，间或有点点村庄若隐若现。东侧的荒山之后，图书馆的顶楼清晰可见。西面是唯一的出入口，小径联通着现实和远方。北侧的工地上一栋栋高楼拔地而起，描绘着城市的方向。这里是城市，也是郊野。我们看见城市的喧嚣，却听见郊野的寂静。")]),v._v(" "),_("p",[v._v("这里离学校确然是极近的。初时自北门跋山涉水而来，仅1300余米。若骑车而来，则需绕行柏枧山路，约6.5km。待创业路修筑，步行之路阻断，但骑行仅需3.5km。如今文景路修筑，骑行至湖边仅2.2km，十分钟即可抵达。")]),v._v(" "),_("p",[v._v("我有过许多喜欢的人。她们或文静，或吵闹，或温柔，或霸道，或俏皮，或理智。我喜欢过每一个不一样的她们，实意或真心。但终究她们都淹没在了茫茫人海里。或许记得，或许忘记。考研似乎是终点，又似乎只是终点。考研后的我，终究失去了一切期待的我，只会将一切沉默以待。")]),v._v(" "),_("p",[v._v("湖水沉默地倾听者一切。我无数次想这么一直从大堤上走下去，走进湖水里，永远消失在湖水里。但我终究还是选择回去面对现实。别人眼中的我，并不是真正的我。没有人知道什么是真正的我。于是也就没有什么会让我开心起来。所谓的龙岗开心故事集，大约也是梦里都不会有的东西吧。")]),v._v(" "),_("p",[v._v("起风了，乌云来了，要下雨了，且归去吧。")]),v._v(" "),_("p",[v._v("到五一的最后一天，阴雨后的宣城又一次绽放出蓝天和白云。骑行出发，穿过植物园，躺在新港的大草坪上。回忆充斥脑海，仿佛现在仍是大二的模样，我还在模电数电电磁场的包围里不得喘息，还在为单片机比赛而做着努力。那时的我失落到了谷底，没有人会叫我大佬，也没人会觉得我是。前尘忆梦，一切仿佛就在昨天，但却然已经不是昨天。现在的我，只不过是离社畜生活只剩三个月的咸鱼而已。")]),v._v(" "),_("p",[v._v("再一次穿过敬亭山的环山南路，在极速下坡的刺激中释放所有的失落。每一次当我心情不好的时候，我都会来到这条路上，让我的老伙计载着我以自行车的最高马力冲下山坡。也无数次想过，只要稍微偏离一下，我也就可以获得长久的安息。但或许，总有什么牵绊着我，流连在这个世界上。但我依然不曾找到，那究竟是什么。")]),v._v(" "),_("p",[v._v("下山不久，便来到了宣城中央绿地。曾经的这里只是一个荒凉的水库，而今却已完全变了模样。音乐喷泉的炫目灯光下，人群熙攘。在失去的两年时光里，宣城还是我熟悉的宣城，却也不再是我熟悉的宣城。回忆越来越多，却又在忘却中越来越少。就像列表里一个个太久不曾联系的老朋友，已经不知道该如何交谈。就像一个个我仍然熟悉的名字，但熟悉的可能也只剩了名字。")]),v._v(" "),_("h2",{attrs:{id:"光·雨"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#光·雨"}},[v._v("#")]),v._v(" 光·雨")]),v._v(" "),_("p",[v._v("一不小心就过去了半个五月，连绵的雨季让时光的流逝都显得有些安静。每天只能工作三小时的摸鱼论文写作机器，在奋战了三天后也生产出了六千多字的学术垃圾。眼前的生活似乎快要结束了，离开一所不那么像大学的大学，去向下一个似乎更像是大学的地方。过去的东西只能让他过去，而未来的东西还是要留给未来。毕竟，故事进行到这里，也差不多快要收场了。幕落，人去楼空，如此而已。")]),v._v(" "),_("p",[v._v("我仍未知道那个给我送奶茶的人是谁，但我并没有什么兴趣去知道了。会记得我很久以前写的一句话的人，或许会是旧友，但必定不属于亲朋，我不喜欢藏在暗处的东西。藏在暗处的东西，就像我自己的感情线一样，要么见光就死，要么无影无踪。姑且就当没有发生过。毕竟，这种注定已经没有结果的东西，是谁也不想去接受的。")]),v._v(" "),_("p",[v._v("关于努力和卷两个词的对比而言，努力和卷之间其实没有什么关系，我们可以说一个人在努力的卷，但也可以说一个人在努力摸鱼。努力是形容词或名词，形容某人做某事很卖力或者卖力做事这样一个过程。而卷是动词，应该与之对标的是奋斗这样的动词。从我的视角看来，奋斗和卷的内核有近似之处，但奋斗的本质是超越自己，是积极的；卷的本质是战胜别人，是消极的。超越自己不一定战胜别人，但自己获得了确确实实的进步；战胜别人不一定超越自己，可能是让大家都陷入无意义的工作。")]),v._v(" "),_("p",[v._v("从这种定义的角度上来讲，我和卷之一字几乎毫无关系。我所做的每一件事，几乎都只是单纯为了我自己的获得感。我对别人的好奇仅仅只在于一种上帝视角下的观望，而从不会把自己代入同一个棋局，即使我身在棋局之中也一样。")]),v._v(" "),_("p",[v._v("但这样的后果也就是，我的内心会总是感觉很孤独。我对所有的一切都不会有太多的代入感，我的生活日常只不过是一部持续更新的互动舞台剧。我会希望有各种各样的新剧情，对日复一日沉闷而繁琐的日常并没有足够的兴趣。既然是剧情，那么意料之外的结局总是常见的。因此尽管我仍会对未来有所期待，但我所期待的更多的则是一种对新鲜感的期待。")]),v._v(" "),_("p",[v._v("甘雨的剧情里，我很喜欢关于绝云间的孤独与璃月港的孤独那一段。应该没有人喜欢孤独，但相较于绝云间的孤独，人潮如织的璃月港的孤独，才是更深的孤独。因此我会选择独自旅行，独自去看我视角里不一样的风景。我期待一个旅行的伴侣，但旅行者，终究应该是孤独的。")]),v._v(" "),_("p",[v._v("橙光游戏《遇龙》的主题曲《遇萤》，讲述的是一场美丽的邂逅与错过。而我的人生里，不会有这般凄清的错付，只会有，故事里落幕的一场戏。当故事回到现实，终究也不会有人去奠祭。")]),v._v(" "),_("h2",{attrs:{id:"浔·觅"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#浔·觅"}},[v._v("#")]),v._v(" 浔·觅")]),v._v(" "),_("p",[v._v("当岁月的指针在光阴的催促下游走，迎面而来的是一年一度五二零的时光。记忆里依然残存的是一地金黄，但迷情的紫罗兰色却已然占领了那一片河谷。沉浸在阴雨连绵里的五月，稀松平常的每一天，只有在夜色里，才会获得一点不多的安宁。感谢，每一个夜色里守候我的灵魂。")]),v._v(" "),_("p",[v._v("大学的生涯就像北门外体育馆旁边的那片河谷，度过了大一大二金黄色的春天，经历了大三那年疫情缺失的遗憾，终于在大四的时候望见了薰衣草的紫色绚烂。足够浪漫，只不过是不属于我的浪漫。五二零，实验室五个人，两个没有打农药，零个人在学习，如此而已。")]),v._v(" "),_("p",[v._v("然而学长讲堂的时候看见一个小姐姐，感觉蛮可爱的。不过又跟我有什么关系呢？")]),v._v(" "),_("p",[v._v("就想起2019年的5月，当我第一次来到南浔的时候，这里的美让我震撼。湛蓝的天空下，小桥、流水、扁舟，古朴的建筑装点着水乡的浪漫。许是离乌镇、西塘、同里都太近的缘故，声名不显的南浔并不像其他几个古镇一样有着太多的人流。那时的我，曾经想过，如果我再一次来南浔，那么，定是要带着那所爱的人一起。")]),v._v(" "),_("p",[v._v("一晃，便到了两年之后的2021年。依然孑然一身的我，又一次来到了这里。经历过了无可奈何，便知道，浪漫不过是表面之上炫目的华彩。或许绚烂，但终究在华光褪去之后，不再有鲜丽的颜色。既已习惯孤独，那就不被孤独所束。我依然孤独，但似乎，也并不孤独。")]),v._v(" "),_("p",[v._v("人生而孤独，行于世间，无所依仗与救赎。祈愿于人海，欲寻求一人与之相合。然人海茫茫，所遇者众，只投缘者无多。人所以为人，盖心有九窍。而心生七面，善恶难辨，是故人不可尽知人，不可尽信人。")]),v._v(" "),_("p",[v._v("资本不眠，而浪漫不死。浪漫依文化而生，与文明共存。凡文明所在之处，皆有浪漫为注脚。俗世艰难，唯有喜欢。喜欢廉价，但是是所有一切里，最高雅的廉价。")]),v._v(" "),_("p",[v._v("人生有起有落，投资可赢可输，但浪漫不渝。INFP的喜欢是病态的喜欢，是非常执着的喜欢，但也是怯懦的喜欢。我可能就是所谓的回避型依恋吧，下意识就会回避情感，就会回避喜欢的人。我害怕亲密关系，会去执着的远离亲密关系。适度的亲近，对我来说，就够了。")]),v._v(" "),_("p",[v._v("所以不论在哪里，朋友总是越来越多，而后越来越少。太久不联系的人，消失在了我的记忆里，也消失在了对方的记忆里。直到很久以后，有人提及，可能才会想起，哦，当时曾经有过这么个人啊。")]),v._v(" "),_("p",[v._v("于是最后的最后，一无所有的我的灵魂，带上一无所有的我的躯体，在天地间独行。我渐渐忘了什么是浪漫本应有的意义。或许，世间的一切都很浪漫，除了人。")]),v._v(" "),_("p",[v._v("毕业论文的致谢，是我人生里写的第一篇致谢，也可能将是最后一篇。我感谢了带给我归属感和依恋感的一切，没有学校，没有家庭，没有出身，只有这整整一年来的点滴温暖。忘却所有不愉快的部分，才能赢得更好的结局。")]),v._v(" "),_("p",[v._v("一切的一切都有两面性，就纵使是魔都也不例外。上海不仅是陆家嘴和外滩，也有青浦的小桥流水。但浪漫，永不缺席。")])])}),[],!1,null,null,null);_.default=a.exports}}]);